typedef struct _devicemodeW {
WCHAR dmDeviceName[CCHDEVICENAME];
WORD  dmSpecVersion;   WORD  dmDriverVersion;   WORD  dmSize;
WORD  dmDriverExtra;
DWORD dmFields;   union {
struct {
short dmOrientation;       short dmPaperSize;       short dmPaperLength;       short dmPaperWidth;
short dmScale;       short dmCopies;
short dmDefaultSource;       short dmPrintQuality;
} DUMMYSTRUCTNAME;     POINTL dmPosition;     struct {
POINTL dmPosition;
DWORD  dmDisplayOrientation;       DWORD  dmDisplayFixedOutput;
} DUMMYSTRUCTNAME2;   } DUMMYUNIONNAME;
short dmColor;   short dmDuplex;
short dmYResolution;
short dmTTOption;   short dmCollate;
WCHAR dmFormName[CCHFORMNAME];
WORD  dmLogPixels;   DWORD dmBitsPerPel;   DWORD dmPelsWidth;   DWORD dmPelsHeight;   union {
DWORD dmDisplayFlags;     DWORD dmNup;
} DUMMYUNIONNAME2;
DWORD dmDisplayFrequency;   DWORD dmICMMethod;
DWORD dmICMIntent;   DWORD dmMediaType;   DWORD dmDitherType;   DWORD dmReserved1;   DWORD dmReserved2;
DWORD dmPanningWidth;   DWORD dmPanningHeight;
} DEVMODEW, *PDEVMODEW, *NPDEVMODEW, *LPDEVMODEW; 成员
dmDeviceName[CCHDEVICENAME]
对于显示，指定显示驱动程序的 DLL 的名称;例如，3Dlabs Permedia3 显示驱动程序的“perm3dd”。
对于打印机，指定“友好名称”;例如，对于 PCL/HP LaserJet，则为“PCL/HP LaserJet”。 如果名称的长度大于 CCHDEVICENAME 字符，则后台处理程序会将其截断以适合数组。
dmSpecVersion
指定此 DEVMODEW 结构的版本号。 当前版本号由 wingdi.h 中的DM_SPECVERSION常量标识。
dmDriverVersion
对于打印机，指定打印机驱动程序开发人员分配的打印机驱动程序版本号。
显示驱动程序可以将此成员设置为 DM_SPECVERSION。 dmSize
指定公共 DEVMODEW 结构的大小（以字节为单位），不包括 dmDriverExtra 成员标识
的任何专用驱动程序指定成员。 dmDriverExtra
指定公共结构成员后面的专用驱动程序数据的字节数。 如果设备驱动程序不提供专用
DEVMODEW 成员，则此成员应设置为零。 dmFields
指定标识以下哪些 DEVMODEW 成员正在使用的位标志。 例如，当 dmOrientation 成员包含有效数据时，将设置DM_ORIENTATION标志。 DM_XXX标志在 wingdi.h 中定义。
DUMMYUNIONNAME
DUMMYUNIONNAME.DUMMYSTRUCTNAME
DUMMYUNIONNAME.DUMMYSTRUCTNAME.dmOrientation
对于打印机，指定纸张方向。 此成员可以是DMORIENT_PORTRAIT或

