typedef struct _CLIPLINE {
POINTFIX ptfxA;   POINTFIX ptfxB;
LONG     lStyleState;   ULONG    c;
RUN      arun[1];
} CLIPLINE, *PCLIPLINE;
成员 ptfxA
指定包含线条起点的 POINTFIX 结构。 ptfxB
指定包含线条终点的 POINTFIX 结构。 lStyleState
驱动程序调用 PATHOBJ_bEnumClipLines 时 GDI 提供的 一对 16 位值。 这两个值打包到 LONG 中，并指定样式偏移量回到线段的第一个像素。 这是如果未剪裁线条时呈现的第一个像素。 此值允许计算行的其余部分的样式。 有关其他信息，请参阅 带样式的修饰线
。 c
指定 运行数组中的 RUN 结构数。 arun[1]
是 RUN 结构的数组。 RUN 结构描述剪裁线的开始和停止部分。
typedef struct _CLIPOBJ {   ULONG iUniq;
RECTL rclBounds;
BYTE  iDComplexity;   BYTE  iFComplexity;   BYTE  iMode;
BYTE  fjOptions;} CLIPOBJ;
成员 iUniq
指定唯一标识剪辑区域的值。 如果 iUniq 不为零，驱动程序会将其用作缓存标识符。 这允许驱动程序在下载和缓存区域后识别该区域。 如果值为零，则驱动程序不应缓存该区
域，因为不会再次使用该区域。 rclBounds
指定一个 RECTL 结构，该结构绑定与绘图相交的区域部分。 如果 iDComplexity

typedef struct _GLYPHBITS {
POINTL ptlOrigin;   SIZEL  sizlBitmap;
BYTE   aj[1];} GLYPHBITS;
成员 ptlOrigin
指定一个 POINTL 结构，该结构定义位图中字符的原点。 sizlBitmap
指定一个 SIZEL 结构，该结构包含位图的宽度和高度（以像素为单位）。 SIZEL 结构与
SIZE 结构相同。 aj[1]
是一个大小可变的字节数组，其中包含字形的 BYTE 对齐位图。 数组必须包含末尾的填充，以 DWORD 对齐整个结构。
GDI 将对具有抗锯齿字体的驱动程序发出此请求， (请参阅 DrvQueryFontCaps) 的说明。驱动程序可能无法以多级格式呈现字体。 在这种情况下，驱动程序调用失败，GDI 将再
次调用驱动程序，请求单色实现。
typedef struct _GLYPHDATA {
GLYPHDEF gdf;   HGLYPH   hg;   FIX      fxD;   FIX      fxA;   FIX      fxAB;
FIX      fxInkTop;
FIX      fxInkBottom;
RECTL    rclInk;   POINTQF  ptqD;} GLYPHDATA;
成员 gdf
指定包含指向 GLYPHBITS 结构或 PATHOBJ 结构的指针的 GLYPHDEF 联合，具体取决于
字形数据是位图还是轮廓格式。 hg
字形的句柄。 fxD
指定包含字符增量量的 FIX 值，D = A + B + C。字符递增量表示 A) (预生成量或左侧边长量的总和、字形 (B) 的宽度以及右侧边带量 (C) 的宽度。 这两个侧角量表示 (通常) 字形左右的空白空间。 fxD 中存储的值是 D 的点积和沿基线 (的单位矢量，以设备坐标) ，生成
D 到基线上的投影。 fxA
指定一个 FIX 值，该值包含预生成量或左侧边带量 A。 fxA 中存储的值是 A 的点积，沿基线 (的单位向量以设备坐标) 表示，从而在基线上生成 A 的投影。
fxAB
指定包含字符 A + B 前行边缘的 FIX 值。fxAB 中存储的值是 A + B 的点积，沿设备坐标)
中沿基线 (的单位矢量，从而生成 A + B 到基线的投影。 fxInkTop
指定一个 FIX 值，该值包含基线与墨盒顶部沿上升方向的单位向量之间的距离， (设备坐标) 。
fxInkBottom
指定一个 FIX 值，该值包含基线与墨迹框底部沿上升方向的单位矢量之间的距离 (设备坐
标) 。 rclInk
指定描述字形所在的墨迹框的 RECTL 结构。 墨迹框的两侧与 x 轴和 y 轴平行。 ptqD
指定包含字符增量向量的 POINTQF 结构，D = A + B + C。 ptqD 的高阶 WORD 为 28.4 设备坐标。 此成员的低序 WORD 提供额外的精度。 有关 POINTQF 结构的说明，请参阅
GDI 数据类型。
typedef union _GLYPHDEF {
GLYPHBITS *pgb;   PATHOBJ   *ppo;} GLYPHDEF;
成员 pgb
如果定义了 pgb ，则此成员是指向 GLYPHBITS 结构的指针。 驱动程序可以使用此结构中
存储的位图位在其表面上形成关联的字形。 ppo
如果定义了 ppo ，则此成员是指向 PATHOBJ 结构的指针，驱动程序可以检查以提取描述
关联字形的路径。
typedef struct _GLYPHPOS {   HGLYPH   hg;
GLYPHDEF *pgdf;   POINTL   ptl;
} GLYPHPOS, *PGLYPHPOS;
成员 hg
字形的句柄。 pgdf
指向 GLYPHDEF 联合的指针。 ptl
指定一个 POINTL 结构，该结构包含设备空间中应放置字形的字符原点的坐标。
